import{_ as a,o as t,c as s,ak as p}from"./chunks/framework.d_5_XLDx.js";const h=JSON.parse('{"title":"【新闻】Stash 疑似大面积“缝合”开源代码","description":"","frontmatter":{"title":"【新闻】Stash 疑似大面积“缝合”开源代码","createTime":"2025/07/05 10:18:57","permalink":"/news/kne6vczb/","tags":["科学上网","VPN","代理软件","Stash Mac","开源代码","抄袭","GPL","AGPL"]},"headers":[],"relativePath":"blog/ermao/新闻/Stash疑似大面积缝合开源代码.md","filePath":"blog/ermao/新闻/Stash疑似大面积缝合开源代码.md","lastUpdated":1769776243000}'),i={name:"blog/ermao/新闻/Stash疑似大面积缝合开源代码.md"};function n(r,e,o,g,m,l){return t(),s("div",null,[...e[0]||(e[0]=[p('<p>接群友匿名投稿，知名代理软件 Stash Mac 涉嫌大量复制粘贴开源代码，涉及多个GPL、AGPL协议下的代码库。</p><p>爆料源：<a href="https://x.com/nek0hasekai/status/1941361311130235189" target="_blank" rel="noreferrer">https://x.com/nek0hasekai/status/1941361311130235189</a></p><h2 id="stash-mac-客户端涉嫌抄袭开源代码" tabindex="-1">Stash Mac 客户端涉嫌抄袭开源代码 <a class="header-anchor" href="#stash-mac-客户端涉嫌抄袭开源代码" aria-label="Permalink to &quot;Stash Mac 客户端涉嫌抄袭开源代码&quot;">​</a></h2><p>据爆料源，Stash Mac 客户端的核心代码（时间戳20250520） 被指控“缝合”多项知名开源项目：</p><ul><li>Shadow-TLS： 疑似完全⬅️ SagerNet/sing-box （GPL授权）。Singbox 开发者公开指控 Stash Mac 抄袭其 Shadow-TLS 实现。</li><li>SS2022： 疑似部分⬅️ database64128/shadowsocks-go （AGPL授权）。</li><li>Vless： 疑似部分⬅️ SagerNet/sing-box （GPL授权）。</li><li>Tun 的 system 栈： 疑似部分⬅️ Kr328/tun2socket（MIT 授权）。</li></ul><p>爆料源还称，Stash Mac 在复制粘贴代码时，甚至忘了对 quic-go 依赖 去重，导致其在代码中重复出现两遍。</p><p>::: collapse</p><ul><li><p>GPL与AGPL协议的版权简介</p><p>GPL协议（GNU General Public License）是开源社区的重要基石，其核心特点是“传染性”。这意味着，如果一个软件 完整或部分 使用了GPL协议的代码并进行分发，那么该软件的整体也必须以GPL协议开源，并提供完整的源代码。</p><p>AGPL协议（GNU Affero General Public License）则是GPL的延伸，专为网络服务（SaaS）设计。它规定，即使软件没有被直接“分发”给用户，只要通过网络向用户提供服务并使用了AGPL许可的代码，服务提供方就必须向用户提供其所使用的、修改后的完整源代码。</p></li></ul><p>:::</p><h2 id="stash-mac-的代码结构与-sagernet-sing-box-完全一致-甚至连文件名都没有修改。" tabindex="-1">Stash Mac 的代码结构与 SagerNet/sing-box 完全一致，甚至连文件名都没有修改。 <a class="header-anchor" href="#stash-mac-的代码结构与-sagernet-sing-box-完全一致-甚至连文件名都没有修改。" aria-label="Permalink to &quot;Stash Mac 的代码结构与 SagerNet/sing-box 完全一致，甚至连文件名都没有修改。&quot;">​</a></h2><p><img src="https://image.ermao.net/images/news/kne6vczb/image.png" alt="alt text"></p><p>为什么说除了 Surge 和火箭以外的苹果代理都不要买，因为他们根本没有自己实现协议的能力，可以相信其他东西实现的也不咋地。</p><p>图片内容来自 Stash 官网下载 macOS 客户端 + strings | grep</p><p>shadow-tls 部分完全复制我的 GPL 代码，文件结构完全一样。</p><p><img src="https://image.ermao.net/images/news/kne6vczb/image-1.png" alt="alt text"></p><p><img src="https://image.ermao.net/images/news/kne6vczb/image-2.png" alt="alt text"></p><p><img src="https://image.ermao.net/images/news/kne6vczb/image-3.png" alt="alt text"></p><blockquote><p>我们现在在 iOS 上虽然比不上还没发布的 Surge 6，但甚至比 Surge 5 快！</p><p>sing-box tf 1.12.0-beta.31 9.9G （p1）</p><p>Surge 5 tf build 3516 5.8G（p2）</p><p>Surge 5 商店版 5.3G （p3）</p><p>设备 iPhone 16 pro</p><p>其他软件太慢了就不放了，不过还发现了点有意思的事情，等会发</p></blockquote><p><img src="https://image.ermao.net/images/news/kne6vczb/image-4.png" alt="alt text"></p><p>ss2022 部分可以相信是来自 AGPL 的 database64128/shadowsocks-go，结构命名非常相似</p><p><img src="https://image.ermao.net/images/news/kne6vczb/image-5.png" alt="alt text"></p><p>vless 部分某些代码与 sing-box 的命名一致</p><p><img src="https://image.ermao.net/images/news/kne6vczb/image-6.png" alt="alt text"></p><p>tun 的 system stack 部分来自 kr328/tun2socket （原 ClashForAndroid 使用），不过授权是 MIT 用了也不算侵权。</p><p><img src="https://image.ermao.net/images/news/kne6vczb/image-7.png" alt="alt text"></p><p><img src="https://image.ermao.net/images/news/kne6vczb/image-8.png" alt="alt text"></p><p>tun 的 system stack 部分来自 kr328/tun2socket （原 ClashForAndroid 使用），不过授权是 MIT 用了也不算侵权。</p><p>tun 的 lwip stack 部分可能来自开源代理软件 leaf 作者 eycorsican 的 netstack-lwip，需要注意的是这个库没有 license，也就是说版权所有不可以使用。</p><p>我相信其他协议实现部分肯定还复制了（包括 mihomo、我的和其他人的）GPL 代码，不过代码量少不反编译就没办法一眼实锤，懒得继续找了。</p><p><img src="https://image.ermao.net/images/news/kne6vczb/image-9.png" alt="alt text"></p>',30)])])}const S=a(i,[["render",n]]);export{h as __pageData,S as default};
